-- Run once in the Supabase SQL editor. PostgreSQL 15+
create extension if not exists pgcrypto;
create type public.user_role as enum ('user','admin'); create type public.difficulty as enum ('easy','medium','hard'); create type public.payment_status as enum ('pending','paid','failed','cancelled','refunded');
create table public.profiles(id uuid primary key references auth.users on delete cascade,full_name text not null default '',phone text not null default '',role public.user_role not null default 'user',points int not null default 0 check(points>=0),is_prime boolean not null default false,prime_until timestamptz,created_at timestamptz not null default now());
create table public.categories(id uuid primary key default gen_random_uuid(),slug text unique not null,title text not null,description text,sort_order int default 0,is_active boolean default true);
create table public.subcategories(id uuid primary key default gen_random_uuid(),category_id uuid not null references public.categories on delete cascade,title text not null,slug text not null,unique(category_id,slug));
create table public.questions(id uuid primary key default gen_random_uuid(),category_id uuid not null references public.categories,subcategory_id uuid references public.subcategories,text text not null,difficulty public.difficulty not null default 'medium',explanation text not null,law_name text not null,law_article text not null,source_url text,law_version_date date not null,verified_by uuid references public.profiles,verified_at timestamptz,needs_review boolean not null default true,is_prime boolean not null default false,is_published boolean not null default false,popularity int not null default 0,created_at timestamptz default now(),updated_at timestamptz default now(),check(not is_published or (verified_at is not null and needs_review=false)));
create table public.question_options(id uuid primary key default gen_random_uuid(),question_id uuid not null references public.questions on delete cascade,option_text text not null,is_correct boolean not null default false,sort_order smallint not null,unique(question_id,sort_order));
create table public.tests(id uuid primary key default gen_random_uuid(),title text not null,category_id uuid references public.categories,subcategory_id uuid references public.subcategories,difficulty public.difficulty,is_prime boolean default false,is_published boolean default false,time_limit_minutes int,created_at timestamptz default now());
create table public.test_questions(test_id uuid references public.tests on delete cascade,question_id uuid references public.questions on delete cascade,sort_order int not null,primary key(test_id,question_id));
create table public.test_attempts(id uuid primary key default gen_random_uuid(),user_id uuid not null references public.profiles on delete cascade,test_id uuid references public.tests,mode text not null check(mode in('learning','exam','timed','thematic','random','mistakes','daily')),started_at timestamptz default now(),completed_at timestamptz,score int,total int,percent numeric(5,2),points_granted boolean default false,question_ids uuid[] not null default '{}');
create table public.user_answers(id uuid primary key default gen_random_uuid(),attempt_id uuid not null references public.test_attempts on delete cascade,question_id uuid not null references public.questions,option_id uuid not null references public.question_options,is_correct boolean not null,answered_at timestamptz default now(),unique(attempt_id,question_id));
create table public.saved_questions(user_id uuid references public.profiles on delete cascade,question_id uuid references public.questions on delete cascade,created_at timestamptz default now(),primary key(user_id,question_id));
create table public.daily_usage(user_id uuid references public.profiles on delete cascade,usage_date date default current_date,questions_used int default 0,primary key(user_id,usage_date));
create table public.subscriptions(id uuid primary key default gen_random_uuid(),user_id uuid references public.profiles on delete cascade,status text not null,starts_at timestamptz,ends_at timestamptz,created_at timestamptz default now());
create table public.user_achievements(id uuid primary key default gen_random_uuid(),user_id uuid references public.profiles on delete cascade,achievement_code text not null,title text not null,description text,earned_at timestamptz default now(),unique(user_id,achievement_code));
create table public.reports(id uuid primary key default gen_random_uuid(),user_id uuid references public.profiles on delete set null,question_id uuid references public.questions on delete cascade,reason text not null,comment text,status text default 'new',admin_response text,created_at timestamptz default now(),reviewed_at timestamptz);
create table public.audit_logs(id bigint generated always as identity primary key,admin_user_id uuid references public.profiles,action text not null,entity_type text not null,entity_id text,old_data jsonb,new_data jsonb,created_at timestamptz default now());
create table public.system_settings(id uuid primary key default gen_random_uuid(),setting_key text unique not null,setting_value jsonb not null,updated_at timestamptz default now());
create table public.payments(id uuid primary key default gen_random_uuid(),user_id uuid references public.profiles on delete cascade,provider text not null,external_order_id text unique not null,amount numeric(12,2) not null,currency char(3) default 'GEL',status public.payment_status default 'pending',payment_url text,provider_response jsonb,created_at timestamptz default now(),paid_at timestamptz,updated_at timestamptz default now());
create table public.certificates(id uuid primary key default gen_random_uuid(),user_id uuid references public.profiles on delete cascade,test_attempt_id uuid unique references public.test_attempts,certificate_code text unique not null default upper(substr(replace(gen_random_uuid()::text,'-',''),1,16)),issued_at timestamptz default now());
create index questions_filter_idx on public.questions(category_id,subcategory_id,difficulty,is_prime) where is_published; create index attempts_user_idx on public.test_attempts(user_id,started_at desc); create index reports_status_idx on public.reports(status,created_at); create index leaderboard_idx on public.profiles(points desc);
create function public.is_admin() returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.profiles where id=auth.uid() and role='admin')$$;
alter table public.profiles enable row level security; alter table public.categories enable row level security; alter table public.subcategories enable row level security; alter table public.questions enable row level security; alter table public.question_options enable row level security; alter table public.tests enable row level security; alter table public.test_questions enable row level security; alter table public.test_attempts enable row level security; alter table public.user_answers enable row level security; alter table public.saved_questions enable row level security; alter table public.daily_usage enable row level security; alter table public.subscriptions enable row level security; alter table public.user_achievements enable row level security; alter table public.reports enable row level security; alter table public.audit_logs enable row level security; alter table public.system_settings enable row level security; alter table public.payments enable row level security; alter table public.certificates enable row level security;
create policy "own profile read" on public.profiles for select using(id=auth.uid() or public.is_admin()); create policy "own profile update" on public.profiles for update using(id=auth.uid()) with check(id=auth.uid() and role=(select role from public.profiles where id=auth.uid()));
create policy "public categories" on public.categories for select using(is_active or public.is_admin()); create policy "public subcategories" on public.subcategories for select using(true); create policy "published questions" on public.questions for select using((is_published and verified_at is not null and not needs_review) or public.is_admin()); create policy "published tests" on public.tests for select using(is_published or public.is_admin());
create policy "admin categories" on public.categories for all using(public.is_admin()) with check(public.is_admin()); create policy "admin subcategories" on public.subcategories for all using(public.is_admin()) with check(public.is_admin()); create policy "admin questions" on public.questions for all using(public.is_admin()) with check(public.is_admin()); create policy "admin options" on public.question_options for all using(public.is_admin()) with check(public.is_admin()); create policy "admin tests" on public.tests for all using(public.is_admin()) with check(public.is_admin());
create policy "own attempts" on public.test_attempts for select using(user_id=auth.uid() or public.is_admin()); create policy "own answers" on public.user_answers for select using(exists(select 1 from public.test_attempts a where a.id=attempt_id and a.user_id=auth.uid()) or public.is_admin()); create policy "own saved" on public.saved_questions for all using(user_id=auth.uid()) with check(user_id=auth.uid()); create policy "own usage" on public.daily_usage for select using(user_id=auth.uid()); create policy "own subscriptions" on public.subscriptions for select using(user_id=auth.uid() or public.is_admin()); create policy "own achievements" on public.user_achievements for select using(user_id=auth.uid()); create policy "create report" on public.reports for insert with check(user_id=auth.uid()); create policy "own report read" on public.reports for select using(user_id=auth.uid() or public.is_admin()); create policy "admin reports" on public.reports for update using(public.is_admin()); create policy "admin audits" on public.audit_logs for select using(public.is_admin()); create policy "settings read" on public.system_settings for select using(true); create policy "settings admin" on public.system_settings for all using(public.is_admin()) with check(public.is_admin()); create policy "own payments" on public.payments for select using(user_id=auth.uid() or public.is_admin()); create policy "public certificates" on public.certificates for select using(true);
create function public.check_daily_usage() returns jsonb language plpgsql security definer set search_path='' as $$declare u int:=0;lim int:=20;prime boolean:=false;begin if auth.uid() is null then raise exception 'AUTH_REQUIRED';end if;select is_prime into prime from public.profiles where id=auth.uid();select coalesce(questions_used,0) into u from public.daily_usage where user_id=auth.uid() and usage_date=current_date;return jsonb_build_object('used',u,'limit',lim,'allowed',prime or u<lim);end$$;
create function public.get_random_questions(p_category uuid default null,p_subcategory uuid default null,p_difficulty public.difficulty default null,p_count int default 10) returns table(id uuid,text text,law_name text,law_article text,law_version_date date) language sql security definer set search_path='' as $$select q.id,q.text,q.law_name,q.law_article,q.law_version_date from public.questions q join public.profiles p on p.id=auth.uid() where q.is_published and q.verified_at is not null and not q.needs_review and (p.is_prime or not q.is_prime) and (p_category is null or q.category_id=p_category) and (p_subcategory is null or q.subcategory_id=p_subcategory) and (p_difficulty is null or q.difficulty=p_difficulty) order by random() limit least(p_count,50)$$;
create function public.start_test_attempt(p_test_id uuid,p_mode text,p_question_ids uuid[]) returns uuid language plpgsql security definer set search_path='' as $$declare aid uuid;begin if auth.uid() is null then raise exception 'AUTH_REQUIRED';end if;if cardinality(p_question_ids)=0 then raise exception 'INVALID_QUESTIONS';end if;insert into public.test_attempts(user_id,test_id,mode,question_ids) values(auth.uid(),p_test_id,p_mode,p_question_ids) returning id into aid;return aid;end$$;
create function public.submit_test_answer(p_attempt_id uuid,p_question_id uuid,p_option_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$declare ok boolean;begin if not exists(select 1 from public.test_attempts where id=p_attempt_id and user_id=auth.uid() and completed_at is null and p_question_id=any(question_ids)) then raise exception 'INVALID_ATTEMPT';end if;select is_correct into ok from public.question_options where id=p_option_id and question_id=p_question_id;insert into public.user_answers(attempt_id,question_id,option_id,is_correct) values(p_attempt_id,p_question_id,p_option_id,ok);insert into public.daily_usage(user_id,usage_date,questions_used) values(auth.uid(),current_date,1) on conflict(user_id,usage_date) do update set questions_used=public.daily_usage.questions_used+1;return jsonb_build_object('accepted',true);end$$;
create function public.grant_test_points(p_attempt_id uuid) returns int language plpgsql security definer set search_path='' as $$declare pts int;begin update public.test_attempts set points_granted=true where id=p_attempt_id and user_id=auth.uid() and completed_at is not null and not points_granted returning score*10 into pts;if pts is null then return 0;end if;update public.profiles set points=points+pts where id=auth.uid();return pts;end$$;
create function public.complete_test_attempt(p_attempt_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$declare c int;t int;p numeric;begin select count(*),count(*) filter(where ua.is_correct) into t,c from public.test_attempts a join public.user_answers ua on ua.attempt_id=a.id where a.id=p_attempt_id and a.user_id=auth.uid() and a.completed_at is null;p:=round(c*100.0/greatest(t,1),2);update public.test_attempts set completed_at=now(),score=c,total=t,percent=p where id=p_attempt_id and user_id=auth.uid() and completed_at is null;if not found then raise exception 'ALREADY_COMPLETED';end if;perform public.grant_test_points(p_attempt_id);return jsonb_build_object('correct',c,'total',t,'percent',p);end$$;
create function public.get_user_statistics() returns jsonb language sql stable security definer set search_path='' as $$select jsonb_build_object('attempts',count(*),'average',coalesce(round(avg(percent),2),0),'best',coalesce(max(percent),0)) from public.test_attempts where user_id=auth.uid() and completed_at is not null$$;
create function public.get_leaderboard(p_limit int default 50) returns table(rank bigint,full_name text,points int) language sql stable security definer set search_path='' as $$select row_number() over(order by points desc),p.full_name,p.points from public.profiles p order by points desc limit least(p_limit,100)$$;
create function public.verify_certificate(p_code text) returns table(full_name text,test_title text,score_percent numeric,issued_at timestamptz) language sql stable security definer set search_path='' as $$select p.full_name,coalesce(t.title,'იურიდიული ტესტი'),a.percent,c.issued_at from public.certificates c join public.profiles p on p.id=c.user_id join public.test_attempts a on a.id=c.test_attempt_id left join public.tests t on t.id=a.test_id where c.certificate_code=p_code$$;
revoke all on function public.grant_test_points(uuid) from public,anon,authenticated;
create function public.handle_new_user() returns trigger language plpgsql security definer set search_path='' as $$begin insert into public.profiles(id,full_name,phone) values(new.id,coalesce(new.raw_user_meta_data->>'full_name',''),coalesce(new.raw_user_meta_data->>'phone',''));return new;end$$; create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
insert into public.system_settings(setting_key,setting_value) values('free_daily_limit','20'),('points_per_answer','10'),('prime_price','19.90'),('daily_question_count','10'),('maintenance_mode','false'),('registration_enabled','true') on conflict do nothing;
